import { useAuth } from "../context/AuthContext";
import { Link, useLocation } from "react-router-dom";

export default function Navbar() {
  const { user, logout } = useAuth();
  const { pathname } = useLocation();

  const navLink = (to, label, icon) => (
    <Link to={to}
      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold transition-all duration-200
        ${pathname === to ? "bg-blue-900 text-white" : "text-slate-600 hover:bg-slate-100"}`}>
      <span>{icon}</span>{label}
    </Link>
  );

  return (
    <nav className="bg-white border-b border-slate-200 shadow-sm sticky top-[52px] z-40">
      <div className="max-w-5xl mx-auto px-4 h-14 flex items-center justify-between">
        <Link to="/" className="font-playfair text-2xl text-blue-900 font-bold">SpeakUp</Link>
        <div className="flex items-center gap-1">
          {navLink("/", "Home", "🏠")}
          {navLink("/dashboard", "Progress", "📊")}
          {navLink("/words", "Words", "📚")}
        </div>
        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-blue-900 text-white flex items-center justify-center font-extrabold text-sm">
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <div className="text-xs">
              <p className="font-bold text-slate-700">{user?.name}</p>
              <p className="text-slate-400">🔥 {user?.streak} day streak</p>
            </div>
          </div>
          <button onClick={logout}
            className="text-xs border border-slate-200 px-3 py-1.5 rounded-lg text-slate-500 hover:border-red-300 hover:text-red-500 transition-all font-bold">
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
}
